const TopologyMap = () => {
    return (
        <div style={{ marginTop: '1rem', color: '#9ca3af', textAlign: 'center', padding: '4rem' }}>
            <h2 style={{ color: '#f3f4f6', marginBottom: '1rem' }}>Topology Map</h2>
            <p>Loading topology...</p>
        </div>
    );
};

export default TopologyMap;
